import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.c3r8iWL8.js";const p=JSON.parse('{"title":"SOP-009: Artifact Publish & Index","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-009-artifact-publish.md","filePath":"sops/SOP-009-artifact-publish.md","lastUpdated":1782929962000}'),i={name:"sops/SOP-009-artifact-publish.md"};function s(l,e,n,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="sop-009-artifact-publish-index" tabindex="-1">SOP-009: Artifact Publish &amp; Index <a class="header-anchor" href="#sop-009-artifact-publish-index" aria-label="Permalink to &quot;SOP-009: Artifact Publish &amp; Index&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> Platform / SRE · <strong>Gate:</strong> G1 (publish)</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Publish Accepted ADRs and Approved specs from Git to human discovery surfaces and AI agent indexes.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>Platform / SRE</td><td><strong>R/A</strong> — pipeline health</td></tr><tr><td>ARCH</td><td>C — content validation</td></tr><tr><td>AIPO</td><td>C — index/RAG config</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Merge to <code>main</code> of files under <code>docs/adr/</code> or <code>specs/</code></li><li>CI publish workflow enabled</li></ul><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><ol><li><strong>Validate on merge</strong> — CI checks: ADR front matter valid, status allowed, links resolve, spec <code>x-status: approved</code> for indexing.</li><li><strong>Build static site</strong> — MkDocs/Docusaurus → S3 bucket <code>artifacts.{org}.com</code>.</li><li><strong>Invalidate CDN</strong> — CloudFront invalidation for <code>/adr/*</code> and <code>/specs/*</code>.</li><li><strong>Sync Backstage</strong> — TechDocs plugin pulls from Git or S3; catalog entity links updated.</li><li><strong>Re-index</strong> — OpenSearch Ingestion (or Kendra) ingests <strong>Accepted ADRs + Approved specs only</strong>.</li><li><strong>MCP refresh</strong> — ADR/spec MCP server cache invalidated or webhook triggered.</li><li><strong>Verify</strong> — Smoke test: MCP <code>search_adr</code> returns new doc within 15 min.</li></ol><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><ul><li>[ ] Static site updated</li><li>[ ] Backstage shows new revision</li><li>[ ] Search index contains document (if status qualifies)</li><li>[ ] MCP returns document in smoke test</li></ul><h2 id="sla" tabindex="-1">SLA <a class="header-anchor" href="#sla" aria-label="Permalink to &quot;SLA&quot;">​</a></h2><ul><li>End-to-end publish: <strong>≤ 15 minutes</strong> from merge</li></ul><h2 id="failure-handling" tabindex="-1">Failure handling <a class="header-anchor" href="#failure-handling" aria-label="Permalink to &quot;Failure handling&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Failure</th><th>Action</th></tr></thead><tbody><tr><td>Index lag</td><td>Page platform on-call; devs use Git path as fallback</td></tr><tr><td>Broken links in ADR</td><td>CI should block merge; if prod index stale, hotfix PR</td></tr></tbody></table><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-002-adr-lifecycle.html">SOP-002</a> · <a href="./SOP-003-spec-approval.html">SOP-003</a> · <a href="./../planning-and-adr.html">planning-and-adr.md</a></li></ul>',18)])])}const f=t(i,[["render",s]]);export{p as __pageData,f as default};
